/**
 * MedX roving accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Roving tabindex for toolbar and tabs.
 */
const ROVING_TOKENS = Object.freeze({
  primary: { value: "a11y-roving-primary", scope: "a11y" },
  secondary: { value: "a11y-roving-secondary", scope: "a11y" },
  muted: { value: "a11y-roving-muted", scope: "a11y" },
  accent: { value: "a11y-roving-accent", scope: "a11y" },
  surface: { value: "a11y-roving-surface", scope: "a11y" },
});

const ROVING_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const ROVING_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const rovingRegistry = new Map();
const ROVING_listeners = new Set();
let ROVING_seq = 0;

function createRovingId(prefix = "medx-a11y-roving") {
  ROVING_seq += 1;
  return `${prefix}-${ROVING_seq}`;
}

function registerRoving(config = {}) {
  const entryId = config.id ?? createRovingId();
  const preset = ROVING_PRESETS[config.preset ?? "default"] ?? ROVING_PRESETS.default;
  const token = ROVING_TOKENS[config.token ?? preset.token] ?? ROVING_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: ROVING_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  rovingRegistry.set(entryId, entry);
  notifyRovingListeners("register", entry);
  return entry;
}

function updateRoving(id, patch = {}) {
  const entry = rovingRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyRovingListeners("update", entry);
  return entry;
}

function resolveRoving(id) {
  const entry = rovingRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listRovingEntries(filter = {}) {
  let items = Array.from(rovingRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onRovingEvent(listener) {
  ROVING_listeners.add(listener);
  return () => ROVING_listeners.delete(listener);
}

function notifyRovingListeners(type, entry) {
  for (const listener of ROVING_listeners) {
    try {
      listener({ type, entry, registrySize: rovingRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:roving] listener error", err.message);
    }
  }
}

function getRovingMetrics() {
  const items = listRovingEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(ROVING_TOKENS).length,
    presets: Object.keys(ROVING_PRESETS).length,
  };
}

async function runMedxRoving() {
  console.log("[medx:ui:a11y:roving] runtime initialized");
  console.log(`[medx:ui:a11y:roving] tokens=${Object.keys(ROVING_TOKENS).length} presets=${Object.keys(ROVING_PRESETS).length}`);

  const events = [];
  onRovingEvent((e) => events.push(e.type));

  const domains = Object.keys(ROVING_SUPPLY_CHAIN);
  const presets = Object.keys(ROVING_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerRoving({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/roving" },
    });
  }

  const first = listRovingEntries()[0];
  if (first) updateRoving(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getRovingMetrics();
  const resolved = first ? resolveRoving(first.id) : null;

  console.log(`[medx:ui:a11y:roving] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:roving] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:roving] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:roving] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:roving] bootstrap complete");
}

module.exports = runMedxRoving;
